<script>
export default {
  name: "gateway", // 这个名字推荐：大写字母开头驼峰法命名。
  props: {},
  components: {},
  directives: {},
  mixins: [],
  data() {
    return {
      pluginType: "",
    };
  },
  computed: {},
  created() {},
  mounted() {},
  activated() {},
  deactivated() {},
  watch: {},
  methods: {
    //前往页面
    toPage({target}) {
      var id = target.id;
      var strHref = "";
      var appCode = document.getElementById("appCode").value;
      var appServerCode = document.getElementById("appServerCode").value;
      //var params={ param1:params1, param2:params2 };
      var params = {
        param1: document.getElementById("param1").value,
        param2: document.getElementById("param2").value,
      };

      if (appCode == "" && appServerCode == "") {
        appCode = "NEPLATNODE";
        appServerCode = "getNode";
        this.execute(id, appCode, appServerCode, params);
      } else if (appCode != "" && appServerCode != "") {
        this.execute(id, appCode, appServerCode, params);
      } else {
        alert("请输入正确的值！");
      }
    },

    execute(id, appCode, appServerCode, params) {
      this.pluginType = id;
      if (id == "getJSON") {
        alert(
          "插件：" +
            id +
            " 应用编码：" +
            appCode +
            " 服务编码：" +
            appServerCode +
            " 参数：" +
            JSON.stringify(params)
        );
        var data = { method: "uploadFjxx" };
        //mam.navigator.ajax.getJSON('appcode_SYS13','data','getJSON', successCallback);
        mam.navigator.ajax.getJSON(
          appCode,
          params,
          appServerCode,
          this.successCallback,
          this.errCallback
        );
      } else if (id == "postJSON") {
        alert(
          "插件：" +
            id +
            " 应用编码：" +
            appCode +
            " 服务编码：" +
            appServerCode +
            " 参数：" +
            JSON.stringify(params)
        );
        mam.navigator.ajax.postJSON(
          appCode,
          params,
          appServerCode,
          this.successCallback,
          this.errCallback
        );
      } else if (id == "get") {
        alert(
          "插件：" +
            id +
            " 应用编码：" +
            appCode +
            " 服务编码：" +
            appServerCode +
            " 参数：" +
            JSON.stringify(params)
        );
        mam.navigator.ajax.get(
          appCode,
          params,
          appServerCode,
          this.successCallback,
          this.errCallback
        );
      } else if (id == "post") {
        alert(
          "插件：" +
            id +
            " 应用编码：" +
            appCode +
            " 服务编码：" +
            appServerCode +
            " 参数：" +
            JSON.stringify(params)
        );
        mam.navigator.ajax.post(
          appCode,
          params,
          appServerCode,
          this.successCallback,
          this.errCallback
        );
      } else if (id == "getJSON2") {
        alert(
          "插件：" +
            id +
            " 应用编码：" +
            appCode +
            " 服务编码：" +
            appServerCode +
            " 参数：" +
            JSON.stringify(params)
        );
        mam.navigator.ajax.getJSONISCP(
          appCode,
          params,
          appServerCode,
          this.successCallback,
          this.errCallback
        );
      } else if (id == "postJSON2") {
        alert(
          "插件：" +
            id +
            " 应用编码：" +
            appCode +
            " 服务编码：" +
            appServerCode +
            " 参数：" +
