          params,
          appServerCode,
          this.successCallback,
          this.errCallback
        );
      }
    },

    successCallback(v) {
      var json = JSON.stringify(v);
      console.log(
        "成功返回 obj  插件类型：  " + this.pluginType + "  返回结果：  " + v
      );
      console.log(
        "成功返回 json  插件类型：  " +
          this.pluginType +
          "  返回结果：  " +
          json
      );
    },
    errCallback(v) {
      var json = JSON.stringify(v);
      console.log(
        "失败返回 obj  插件类型：  " + this.pluginType + "  返回结果：  " + v
